+/// Microseconds per second.
+const US_PER_SEC: i64 = 1_000_000;
+
+/// Build the complete corpus of all canonical scenarios.
+#[must_use]
+pub fn all_scenarios() -> Vec<ScenarioManifest> {
+    ScenarioId::all()
+        .iter()
+        .map(|id| build_scenario(*id))
+        .collect()
+}
